import { describe, expect, it } from 'vitest';

import {
  BOSONIC_STRING_DIMENSION,
  COUPLING_CONSTANT,
  COST_ALGEBRA_AXES,
  M_THEORY_DIMENSION,
  SUPERSTRING_DIMENSION,
  allStandardModelFermions,
  axisSetTotal,
  baryon,
  darkDoesNotIntersectSM,
  darkPhaseCount,
  darkSkyrmsEquilibrium,
  eleventhDimensionIsCoupling,
  fermionPaysExclusionTax,
  fermionPauliExclusionEntropy,
  fermionPhaseCount,
  fermionSkyrmsEquilibrium,
  isNahmMinimal,
  meson,
  nahmSandwichDimension,
  phaseTransitionDistance,
  type DarkSectorParticle,
  type NahmMinimalAxisSet,
  type StandardModelFermion,
} from '../src/particle-physics';
import {
  TOWER_CEILINGS,
  vacuumBuleyProjection,
  type BuleyProjection,
} from '../src/spectral-noise-monitor';

describe('fermion catalog', () => {
  it('has exactly 24 fermions (3 generations × 4 flavors × 2 sides)', () => {
    expect(allStandardModelFermions.length).toBe(24);
  });

  it('all fermions share the Dodecagon ceiling (12)', () => {
    const sample: StandardModelFermion = {
      generation: 'first',
      flavor: 'quarkUp',
      side: 'particle',
    };
    expect(fermionPhaseCount(sample)).toBe(TOWER_CEILINGS.dodecagon);
    expect(fermionPhaseCount(sample)).toBe(12);
  });

  it('a score-12 carrier sits at the fermion equilibrium', () => {
    const b: BuleyProjection = { waste: 4, opportunity: 4, diversity: 4, score: 12 };
    const f: StandardModelFermion = {
      generation: 'first',
      flavor: 'quarkUp',
      side: 'particle',
    };
    expect(fermionSkyrmsEquilibrium(b, f)).toBe(true);
  });

  it('Pauli exclusion: cloning a fermion costs its score', () => {
    const b: BuleyProjection = { waste: 4, opportunity: 4, diversity: 4, score: 12 };
    expect(fermionPauliExclusionEntropy(b)).toBe(12);
    expect(fermionPaysExclusionTax(b)).toBe(true);
  });

  it('vacuum is the unique state that does NOT pay the Pauli tax', () => {
    expect(fermionPaysExclusionTax(vacuumBuleyProjection)).toBe(false);
    expect(fermionPauliExclusionEntropy(vacuumBuleyProjection)).toBe(0);
  });
});

describe('composite particles', () => {
  it('meson energy is the sum of constituent scores', () => {
    const q: BuleyProjection = { waste: 4, opportunity: 0, diversity: 0, score: 4 };
    const qbar: BuleyProjection = { waste: 4, opportunity: 0, diversity: 0, score: 4 };
    const m = meson(q, qbar);
    expect(m.kind).toBe('meson');
    expect(m.totalEnergy).toBe(8);
    expect(m.constituents.length).toBe(2);
  });

  it('proton: three light quarks at total energy 12', () => {
    const u: BuleyProjection = { waste: 4, opportunity: 0, diversity: 0, score: 4 };
    const d: BuleyProjection = { waste: 0, opportunity: 4, diversity: 0, score: 4 };
    const proton = baryon(u, u, d);
    expect(proton.kind).toBe('baryon');
    expect(proton.totalEnergy).toBe(12);
    expect(proton.constituents.length).toBe(3);
  });

  it('Dodecagon-load meson sits at total energy 24', () => {
    const q: BuleyProjection = { waste: 4, opportunity: 4, diversity: 4, score: 12 };
    const m = meson(q, q);
    expect(m.totalEnergy).toBe(24);
  });
});

describe('dark sector', () => {
  it('Hexon dark wall sits at phase 6', () => {
    expect(darkPhaseCount({ kind: 'hexon', index: 0 })).toBe(6);
  });

  it('Decagon dark wall sits at phase 10 (string-theory signature)', () => {
    expect(darkPhaseCount({ kind: 'decagon' })).toBe(10);
  });

  it('Hendecagon dark wall sits at phase 11 (M-theory signature)', () => {
    expect(darkPhaseCount({ kind: 'hendecagon' })).toBe(11);
  });

  it('every dark wall avoids SM walls (0, 3, 8, 12)', () => {
    const candidates: DarkSectorParticle[] = [
      { kind: 'hexon', index: 0 },
      { kind: 'pentagon' },
      { kind: 'septagon' },
      { kind: 'decagon' },
      { kind: 'hendecagon' },
    ];
    for (const d of candidates) {
      expect(darkDoesNotIntersectSM(d)).toBe(true);
    }
  });

  it('a score-6 carrier is at a Hexon dark equilibrium', () => {
    const b: BuleyProjection = { waste: 2, opportunity: 2, diversity: 2, score: 6 };
    expect(darkSkyrmsEquilibrium(b, { kind: 'hexon', index: 0 })).toBe(true);
  });
});

describe('phase transitions and dimension ladder', () => {
  it('phase-transition distance is symmetric', () => {
    expect(phaseTransitionDistance(8, 10)).toBe(2);
    expect(phaseTransitionDistance(10, 8)).toBe(2);
  });

  it('Decagon = Octagon + 2 (bisided lift)', () => {
    expect(phaseTransitionDistance(8, 10)).toBe(2);
  });

  it('Hendecagon = Decagon + 1 (clinamen)', () => {
    expect(phaseTransitionDistance(10, 11)).toBe(1);
  });

  it('Dodecagon = Hendecagon + 1 (clinamen)', () => {
    expect(phaseTransitionDistance(11, 12)).toBe(1);
  });
});

describe('superstring dimension derivation', () => {
  it('cost-algebra axes sum to 10', () => {
    expect(SUPERSTRING_DIMENSION).toBe(10);
    const total =
      COST_ALGEBRA_AXES.buleFaces +
      COST_ALGEBRA_AXES.biSided +
      COST_ALGEBRA_AXES.temporal +
      COST_ALGEBRA_AXES.vacuum +
      COST_ALGEBRA_AXES.clinamen;
    expect(total).toBe(10);
  });

  it('M-theory = superstring + 1 (gauge orientation)', () => {
    expect(M_THEORY_DIMENSION).toBe(11);
    expect(M_THEORY_DIMENSION - SUPERSTRING_DIMENSION).toBe(1);
  });

  it('bosonic = superstring + 16 (doubled Octagon)', () => {
    expect(BOSONIC_STRING_DIMENSION).toBe(26);
    expect(BOSONIC_STRING_DIMENSION - SUPERSTRING_DIMENSION).toBe(16);
  });

  it("Witten's identification: 11th dimension IS the coupling constant", () => {
    expect(COUPLING_CONSTANT).toBe(1);
    expect(eleventhDimensionIsCoupling()).toBe(true);
  });
});

describe('Nahm sandwich: 10 ≤ d ≤ 11', () => {
  const superstring: NahmMinimalAxisSet = {
    buleFaces: 3,
    biSided: 2,
    temporal: 3,
    vacuum: 1,
    clinamen: 1,
    gauge: 0,
    doubledOctagon: 0,
  };

  const mTheory: NahmMinimalAxisSet = {
    buleFaces: 3,
    biSided: 2,
    temporal: 3,
    vacuum: 1,
    clinamen: 1,
    gauge: 1,
    doubledOctagon: 0,
  };

  const bosonic: NahmMinimalAxisSet = {
    buleFaces: 3,
    biSided: 2,
    temporal: 3,
    vacuum: 1,
    clinamen: 1,
    gauge: 0,
    doubledOctagon: 16,
  };

  it('superstring axis set is Nahm-minimal at total 10', () => {
    expect(isNahmMinimal(superstring)).toBe(true);
    expect(axisSetTotal(superstring)).toBe(10);
    expect(nahmSandwichDimension(superstring)).toBe(10);
  });

  it('M-theory axis set is Nahm-minimal at total 11', () => {
    expect(isNahmMinimal(mTheory)).toBe(true);
    expect(axisSetTotal(mTheory)).toBe(11);
    expect(nahmSandwichDimension(mTheory)).toBe(11);
  });

  it('bosonic axis set is NOT Nahm-minimal (has doubled Octagon)', () => {
    expect(isNahmMinimal(bosonic)).toBe(false);
    expect(axisSetTotal(bosonic)).toBe(26);
    expect(nahmSandwichDimension(bosonic)).toBeNull();
  });

  it('a non-minimal axis set (gauge=2) is excluded from the sandwich', () => {
    const oversized: NahmMinimalAxisSet = {
      buleFaces: 3,
      biSided: 2,
      temporal: 3,
      vacuum: 1,
      clinamen: 1,
      gauge: 2,
      doubledOctagon: 0,
    };
    expect(isNahmMinimal(oversized)).toBe(false);
    expect(nahmSandwichDimension(oversized)).toBeNull();
  });
});
